#include <bits/stdc++.h>
using namespace std;
using ull = unsigned long long;
int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin>>T)) return 0;
    const ull BASE = 91138233ULL;
    while(T--){
        int N; string s; cin>>N>>s;
        vector<ull> pref(N+1,0), pw(N+1,1);
        for(int i=0;i<N;i++){
            pref[i+1]=pref[i]*BASE + (ull)(s[i]);
            pw[i+1]=pw[i]*BASE;
        }
        auto getHash=[&](int l,int r)->ull{ // [l,r)
            return pref[r] - pref[l]*pw[r-l];
        };
        int len=N; bool canRemove=true; bool ok=true;
        while(len>0){
            if(len%2==0 && getHash(0,len/2)==getHash(len/2,len)){
                len/=2; canRemove=true;
            }else if(canRemove){
                len--; canRemove=false;
            }else{ ok=false; break; }
        }
        cout<<(ok?"YES":"NO")<<"\n";
    }
    return 0;
}

