import java.io.*;
import java.util.*;

public class Main {
    static final long BASE = 91138233L;
    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        int T = fs.nextInt();
        StringBuilder out = new StringBuilder();
        while (T-- > 0) {
            int N = fs.nextInt();
            char[] s = fs.next().toCharArray();
            long[] pref = new long[N + 1];
            long[] pw = new long[N + 1];
            pw[0] = 1;
            for (int i = 0; i < N; i++) {
                pref[i + 1] = pref[i] * BASE + s[i];
                pw[i + 1] = pw[i] * BASE;
            }
            int len = N;
            boolean canRemove = true;
            boolean ok = true;
            while (len > 0) {
                if (len % 2 == 0 && hash(pref, pw, 0, len / 2) == hash(pref, pw, len / 2, len)) {
                    len /= 2;
                    canRemove = true;
                } else if (canRemove) {
                    len--;
                    canRemove = false;
                } else {
                    ok = false;
                    break;
                }
            }
            out.append(ok ? "YES" : "NO").append('\n');
        }
        System.out.print(out.toString());
    }
    static long hash(long[] pref, long[] pw, int l, int r) { // [l,r)
        return pref[r] - pref[l] * pw[r - l];
    }
    // Fast scanner for large input
    static class FastScanner {
        private final InputStream in;
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;
        FastScanner(InputStream in) { this.in = in; }
        private int readByte() throws IOException {
            if (ptr >= len) {
                len = in.read(buffer);
                ptr = 0;
                if (len <= 0) return -1;
            }
            return buffer[ptr++];
        }
        String next() throws IOException {
            StringBuilder sb = new StringBuilder();
            int c;
            while ((c = readByte()) != -1 && c <= ' ') {}
            while (c != -1 && c > ' ') {
                sb.append((char) c);
                c = readByte();
            }
            return sb.toString();
        }
        int nextInt() throws IOException { return Integer.parseInt(next()); }
    }
}

