const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/);
let idx = 0;
const T = Number(input[idx++]);
const BASE = 91138233n;
let output = [];
for (let t = 0; t < T; ++t) {
  const N = Number(input[idx++]);
  const s = input[idx++];
  const pref = new Array(N + 1).fill(0n);
  const pw = new Array(N + 1).fill(1n);
  for (let i = 0; i < N; ++i) {
    pref[i + 1] = pref[i] * BASE + BigInt(s.charCodeAt(i));
    pw[i + 1] = pw[i] * BASE;
  }
  const getHash = (l, r) => pref[r] - pref[l] * pw[r - l]; // [l, r)
  let len = N;
  let canRemove = true;
  let ok = true;
  while (len > 0) {
    if (len % 2 === 0 && getHash(0, len / 2) === getHash(len / 2, len)) {
      len = len / 2;
      canRemove = true;
    } else if (canRemove) {
      len--;
      canRemove = false;
    } else {
      ok = false;
      break;
    }
  }
  output.push(ok ? 'YES' : 'NO');
}
